import { MapContainer, TileLayer } from "react-leaflet";
import { useEffect, useState } from "react";
import PlaneMarker from "../components/PlaneMarker";
import FlightPath from "../components/FlightPath";
import "leaflet/dist/leaflet.css";

export default function Dashboard() {
  const start = [12.9716, 77.5946];
  const end = [19.076, 72.8777];

  const [progress, setProgress] = useState(0);
  const [position, setPosition] = useState(start);
  const [rotation, setRotation] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setProgress((p) => (p >= 1 ? 0 : p + 0.002));
    }, 16); // smooth 60fps

    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    const lat = start[0] + (end[0] - start[0]) * progress;
    const lng = start[1] + (end[1] - start[1]) * progress;

    setPosition([lat, lng]);

    const angle =
      (Math.atan2(end[1] - start[1], end[0] - start[0]) * 180) / Math.PI;

    setRotation(angle);
  }, [progress]);

  return (
    <MapContainer center={position} zoom={5} style={{ height: "100vh" }}>
      <TileLayer url="https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png" />

      <PlaneMarker position={position} rotation={rotation} />
      <FlightPath />
    </MapContainer>
  );
}
